export async function loadProjectReport(userId: string, projectId: string) {
  const ownerScope = await loadOwnedProjects(userId);
  const project = ownerScope.find((entry) => entry.id === projectId);
  if (project === undefined) {
    throw new Error("project not found");
  }
  return renderReport(project);
}
